class Solution {
public:
    Solution(double radius, double x_center, double y_center) : radius(radius), x_center(x_center), y_center(y_center) {}

    vector<double> randPoint() {
        double r = sqrt(rand() / static_cast<double>(RAND_MAX)) * radius;
        double theta = rand() / static_cast<double>(RAND_MAX) * 2 * M_PI;
        return {x_center + r * cos(theta), y_center + r * sin(theta)};
    }

private:
    double radius;
    double x_center;
    double y_center;
};
